webpackJsonp([7442054281471],{401:function(e,s){e.exports={data:{markdownRemark:{html:'<p>This past week I presented my first talk at our monthly <a href="http://www.meetup.com/refresh-baton-rouge/">Refresh Baton Rouge meetup</a>. The talk focused on SVG and covered a wide range of topics and use cases.</p>\n<script async class="speakerdeck-embed" data-id="42994830533d013288cb2abbfe1c037c" data-ratio="1.33333333333333" src="//speakerdeck.com/assets/embed.js"></script>\n<p>The talk focused on the following topics:</p>\n<ul>\n<li>Why use SVG?</li>\n<li>Compression</li>\n<li>Accessibility</li>\n<li>Creating SVGs</li>\n<li>Embedding SVGs</li>\n<li>Styling SVGs</li>\n<li>Making SVGs Responsive</li>\n<li>Adaptive SVGs using Media Queries</li>\n<li>SVG Animation</li>\n<li>SVG icon system</li>\n</ul>',frontmatter:{title:"Let's Use SVG - Refresh Baton Rouge"}}},pathContext:{slug:"/posts/2014-11-26-Lets-Us-SVG/"}}}});
